 if(m.history.length===0||m.mesh.position.distanceTo(m.history[m.history.length-1])>3){m.history.push(m.mesh.position.clone());if(m.history.length>90)m.history.shift();m.path.geometry.dispose();m.path.geometry=new THREE.BufferGeometry().setFromPoints(m.history);}
 if(range<6){const nearestSam=interceptors.filter(i=>i.mesh.visible).reduce((best,i)=>Math.min(best,i.mesh.position.distanceTo(m.mesh.position)),Infinity);m.phase='destroyed';m.mesh.visible=false;leakers++;hullIntegrity=Math.max(0,hullIntegrity-profile.damage);createShipDamage(m.mesh.position,profile.damage);destroyMissileVisual(m,'impact');log(`${m.kind} IMPACT / ${profile.damage}% DAMAGE / SAM ${Number.isFinite(nearestSam)?(nearestSam/WORLD_UNITS_PER_KM).toFixed(1)+' km':'NONE'} / HULL ${hullIntegrity}%`);updateShipStatus();if(hullIntegrity<=0){phaseEl.textContent='USS LONG BEACH DISABLED';finishMission(false);}}
