function updateTargetMarker(){const selected=missiles[selectedTargetId-1],track=combatPicture.tracks.get(selectedTargetId);if(!selected||selected.phase==='destroyed'||elapsed<selected.launchAt||!track){targetMarker.style.display='none';return;}const projected=track.position.clone().project(camera),behind=projected.z<-1||projected.z>1,rawX=(projected.x*.5+.5)*innerWidth,rawY=(-projected.y*.5+.5)*innerHeight,margin=innerWidth<560?28:46,safeTop=innerWidth<560?250:76,safeBottom=innerWidth<560?220:110,centerX=innerWidth*.5,centerY=innerHeight*.5,angle=Math.atan2(rawY-centerY,rawX-centerX),displayX=behind?centerX+Math.cos(angle+Math.PI)*innerWidth:centerX+Math.cos(angle)*innerWidth,displayY=behind?centerY+Math.sin(angle+Math.PI)*innerHeight:centerY+Math.sin(angle)*innerHeight,x=Math.max(margin,Math.min(innerWidth-margin,behind?displayX:rawX)),y=Math.max(safeTop,Math.min(innerHeight-safeBottom,behind?displayY:rawY)),offscreen=behind||rawX<margin||rawX>innerWidth-margin||rawY<safeTop||rawY>innerHeight-safeBottom,range=track.position.distanceTo(defender.position),tti=Math.max(0,Math.round(range/Math.max(1,track.velocity.length())));targetMarker.style.display='block';targetMarker.style.left=`${x}px`;targetMarker.style.top=`${y}px`;targetMarker.style.setProperty('--bearing',`${Math.atan2((behind?displayY:rawY)-centerY,(behind?displayX:rawX)-centerX)}rad`);targetMarker.classList.toggle('offscreen',offscreen);targetMarker.classList.toggle('right-edge',x>innerWidth-180);targetMarkerLabel.textContent=`T${String(selectedTargetId).padStart(2,'0')} ${track.classification==='classified'?selected.kind:track.classification.toUpperCase()} / ${tti}s / ±${(track.uncertainty/1000).toFixed(1)}km`;}
function tick(now:number){
 const realDt=Math.min((now-last)/1000,.1);last=now;
 if(running){simAccumulator+=realDt*timeScale;while(simAccumulator>=.05&&running){elapsed+=.05;updateCombat(.05);missiles.forEach(m=>updateIncomingMissile(m,.05));simAccumulator-=.05;}const activeMissiles=missiles.filter(m=>m.phase!=='destroyed'&&elapsed>=m.launchAt),live=activeMissiles.length,distances=activeMissiles.map(m=>m.mesh.position.distanceTo(defender.position));document.querySelector('#targetCount')!.textContent=`${live} ACTIVE / ${missiles.filter(m=>m.phase!=='destroyed').length-live} RESERVE / ${distances.length?(Math.max(...distances)/10).toFixed(1):'0.0'} km`;}
 for(let i=0;i<seaPositions.count;i++){const p=i*3,x=seaBase[p],y=seaBase[p+1];seaPositions.setZ(i,Math.sin(x*.026+elapsed*.72)*.48+Math.sin(y*.019-elapsed*.54)*.34+Math.sin((x+y)*.011+elapsed*.31)*.2);}seaPositions.needsUpdate=true;if(++waveFrame%8===0)seaGeometry.computeVertexNormals();
 missiles.forEach((m,index)=>{if(!m.mesh.visible)return;const pulse=.88+Math.sin(elapsed*19+index*1.7)*.12;(m.mesh.userData.exhaust as THREE.Mesh|undefined)?.scale.set(1,pulse,1);(m.mesh.userData.hotCore as THREE.Mesh|undefined)?.scale.setScalar(.9+pulse*.12);(m.mesh.userData.seaMist as THREE.Mesh|undefined)?.scale.set(1+pulse*.12,1+pulse*.28,1+pulse*.12);const shock=m.mesh.userData.shockCone as THREE.Mesh|undefined;if(shock)(shock.material as THREE.MeshBasicMaterial).opacity=.09+pulse*.035;});
 clockEl.textContent=`${String(Math.floor(elapsed/60)).padStart(2,'0')}:${String(Math.floor(elapsed%60)).padStart(2,'0')}`;updateCamera();if(defender.userData.highDetail)defender.userData.highDetail.visible=camera.position.distanceTo(defender.position)<270;defender.userData.smokePuffs?.forEach((puff:THREE.Mesh,index:number)=>{const life=(elapsed*.22+index/9)%1;puff.position.set(-4-life*7,15+life*11,Math.sin(index*2.1+life*4)*.8);puff.scale.setScalar(.55+life*2.1);(puff.material as THREE.MeshBasicMaterial).opacity=.13*(1-life);});shipDamageEffects.forEach(effect=>{effect.fire.scale.setScalar(.8+Math.sin(elapsed*13+effect.seed)*.22);effect.light.intensity=3.5+Math.sin(elapsed*17+effect.seed)*1.5;effect.smoke.forEach((puff,index)=>{const life=(elapsed*.28+index/effect.smoke.length+effect.seed)%1;puff.position.set(-life*2,1+life*9,Math.sin(effect.seed+index*1.7)*.7);puff.scale.setScalar(.5+life*2.4);(puff.material as THREE.MeshBasicMaterial).opacity=.32*(1-life);});});updateTargetMarker();renderer.render(scene,camera);requestAnimationFrame(tick);
}
